const userId = $json.user_id || "U001";
const originalMessage = $json.message || "";
const message = originalMessage.toLowerCase();

// Dataset reducido de prueba para Carmen.
// Más adelante esta parte se sustituirá por lectura del dataset completo.
const transactions = [
  {
    transaction_id: "T001",
    user_id: "U001",
    date: "2026-01-01",
    description: "Pensión Seguridad Social",
    merchant: "Seguridad Social",
    amount: 980,
    category: "pension",
    balance_after: 2430
  },
  {
    transaction_id: "T002",
    user_id: "U001",
    date: "2026-01-03",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -18.5,
    category: "farmacia",
    balance_after: 2411.5
  },
  {
    transaction_id: "T003",
    user_id: "U001",
    date: "2026-01-05",
    description: "Supermercado Mercadona",
    merchant: "Mercadona",
    amount: -42.3,
    category: "supermercado",
    balance_after: 2369.2
  },
  {
    transaction_id: "T004",
    user_id: "U001",
    date: "2026-01-07",
    description: "Recibo luz",
    merchant: "Endesa",
    amount: -64.8,
    category: "luz",
    balance_after: 2304.4
  },
  {
    transaction_id: "T005",
    user_id: "U001",
    date: "2026-01-10",
    description: "Comisión mantenimiento",
    merchant: "Banco",
    amount: -15,
    category: "comision",
    balance_after: 2289.4
  },
  {
    transaction_id: "T006",
    user_id: "U001",
    date: "2026-01-12",
    description: "Supermercado Mercadona",
    merchant: "Mercadona",
    amount: -36.9,
    category: "supermercado",
    balance_after: 2252.5
  },
  {
    transaction_id: "T007",
    user_id: "U001",
    date: "2026-01-15",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -12.75,
    category: "farmacia",
    balance_after: 2239.75
  },
  {
    transaction_id: "T008",
    user_id: "U001",
    date: "2026-01-18",
    description: "Retirada cajero",
    merchant: "Cajero Banco",
    amount: -50,
    category: "retirada_efectivo",
    balance_after: 2189.75
  },
  {
    transaction_id: "T009",
    user_id: "U001",
    date: "2026-01-20",
    description: "Recibo teléfono",
    merchant: "Movistar",
    amount: -29.9,
    category: "telefono",
    balance_after: 2159.85
  },
  {
    transaction_id: "T010",
    user_id: "U001",
    date: "2026-01-22",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -12.75,
    category: "farmacia",
    balance_after: 2147.1
  },
  {
    transaction_id: "T011",
    user_id: "U001",
    date: "2026-01-22",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -12.75,
    category: "farmacia",
    balance_after: 2134.35,
    anomaly_type: "duplicado"
  },
  {
    transaction_id: "T012",
    user_id: "U001",
    date: "2026-01-25",
    description: "Comisión extraordinaria",
    merchant: "Banco",
    amount: -39,
    category: "comision",
    balance_after: 2095.35,
    anomaly_type: "comision_inusual"
  }
];

const userTransactions = transactions.filter(t => t.user_id === userId);

let answer = "";
let intent_detected = "";
let source_records = [];
let calculation = null;
let alert = false;
let alert_type = null;

// Función auxiliar para sumar gastos por categoría
function totalByCategory(category) {
  const records = userTransactions.filter(t => t.category === category);
  const total = records.reduce((sum, t) => sum + Math.abs(t.amount), 0);

  return {
    records,
    total
  };
}

// 1. Consulta de pensión
if (message.includes("pensión") || message.includes("pension")) {
  intent_detected = "consulta_pension";

  const pension = userTransactions.find(t => t.category === "pension");

  if (pension) {
    answer = `Sí, Carmen. La pensión aparece registrada el ${pension.date} por un importe de ${pension.amount} euros.`;
    source_records = [pension.transaction_id];
    calculation = {
      type: "single_record_lookup",
      amount: pension.amount
    };
  } else {
    answer = "No he encontrado ningún ingreso de pensión en los movimientos disponibles.";
  }

// 2. Consulta de farmacia
} else if (message.includes("farmacia") || message.includes("medicina") || message.includes("medicamentos")) {
  intent_detected = "consulta_gasto_farmacia";

  const result = totalByCategory("farmacia");
  answer = `Carmen, según los movimientos disponibles, has gastado ${result.total.toFixed(2)} euros en farmacia.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "farmacia",
    total: Number(result.total.toFixed(2))
  };

// 3. Consulta de supermercado
} else if (message.includes("supermercado") || message.includes("compra") || message.includes("mercadona")) {
  intent_detected = "consulta_gasto_supermercado";

  const result = totalByCategory("supermercado");
  answer = `Carmen, según los movimientos disponibles, has gastado ${result.total.toFixed(2)} euros en supermercado.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "supermercado",
    total: Number(result.total.toFixed(2))
  };

// 4. Consulta de luz / recibos
} else if (message.includes("luz") || message.includes("endesa") || message.includes("recibo")) {
  intent_detected = "consulta_recibo_luz";

  const result = totalByCategory("luz");
  answer = `Carmen, el recibo de luz disponible en los movimientos es de ${result.total.toFixed(2)} euros.`;
  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "luz",
    total: Number(result.total.toFixed(2))
  };

// 5. Consulta de comisiones
} else if (message.includes("comisión") || message.includes("comision") || message.includes("comisiones")) {
  intent_detected = "consulta_comisiones";

  const result = totalByCategory("comision");
  const unusualCommissions = result.records.filter(t => t.anomaly_type === "comision_inusual");

  if (unusualCommissions.length > 0) {
    alert = true;
    alert_type = "comision_inusual";
    answer = `Carmen, he encontrado comisiones por un total de ${result.total.toFixed(2)} euros. Además, hay una comisión inusual de ${Math.abs(unusualCommissions[0].amount).toFixed(2)} euros que convendría revisar.`;
  } else {
    answer = `Carmen, he encontrado comisiones por un total de ${result.total.toFixed(2)} euros.`;
  }

  source_records = result.records.map(t => t.transaction_id);
  calculation = {
    type: "category_sum",
    category: "comision",
    total: Number(result.total.toFixed(2))
  };

// 6. Consulta de saldo
} else if (message.includes("saldo") || message.includes("dinero") || message.includes("cuánto tengo") || message.includes("cuanto tengo")) {
  intent_detected = "consulta_saldo";

  const lastTransaction = userTransactions[userTransactions.length - 1];

  answer = `Carmen, el último saldo disponible es de ${lastTransaction.balance_after.toFixed(2)} euros.`;
  source_records = [lastTransaction.transaction_id];
  calculation = {
    type: "last_balance",
    balance_after: Number(lastTransaction.balance_after.toFixed(2))
  };

// 7. Detección de duplicados
} else if (message.includes("duplicado") || message.includes("cobrado dos veces") || message.includes("dos veces")) {
  intent_detected = "consulta_cargo_duplicado";

  const duplicates = userTransactions.filter(t => t.anomaly_type === "duplicado");

  if (duplicates.length > 0) {
    alert = true;
    alert_type = "cargo_duplicado";
    answer = `Carmen, he detectado un posible cargo duplicado en ${duplicates[0].merchant} por ${Math.abs(duplicates[0].amount).toFixed(2)} euros. Conviene revisarlo antes de asumir que es correcto.`;
    source_records = duplicates.map(t => t.transaction_id);
    calculation = {
      type: "anomaly_detection",
      anomaly_type: "duplicado",
      count: duplicates.length
    };
  } else {
    answer = "No he encontrado cargos duplicados en los movimientos disponibles.";
    calculation = {
      type: "anomaly_detection",
      anomaly_type: "duplicado",
      count: 0
    };
  }

// 8. Fallback
} else {
  intent_detected = "consulta_no_reconocida";
  answer = "Puedo ayudarte a consultar la pensión, el saldo, gastos de farmacia, supermercado, recibos de luz, comisiones o posibles cargos duplicados.";
}

return [
  {
    json: {
      user_id: userId,
      original_message: originalMessage,
      intent_detected,
      answer,
      source_records,
      calculation,
      alert,
      alert_type,
      numeric_data_from_dataset: true,
      module: "C4_GESTION_FINANCIERA_INTERMEDIA"
    }
  }
];
